import{_ as a,o as e,c as i,ae as l}from"./chunks/framework.EHGTsUvI.js";const u=JSON.parse('{"title":"AI 专栏导读：从模型原理到工程落地","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/intro.md","filePath":"ai-tutorial/intro.md"}'),o={name:"ai-tutorial/intro.md"};function d(s,t,n,r,c,h){return e(),i("div",null,[...t[0]||(t[0]=[l(`<h1 id="ai-专栏导读-从模型原理到工程落地" tabindex="-1">AI 专栏导读：从模型原理到工程落地 <a class="header-anchor" href="#ai-专栏导读-从模型原理到工程落地" aria-label="Permalink to &quot;AI 专栏导读：从模型原理到工程落地&quot;">​</a></h1><blockquote><p>如果你点进这个专题，是希望看到一套“讲完概念就散场”的 AI 科普，那这里大概不会走那条路。 我更想把它写成一组真的能陪工程师往下走的文章：不只讲机制，也讲代价；不只讲做法，也讲什么时候别做；不只追求信息量，还要尽量让你读完能带走一点判断力。</p></blockquote><div class="info custom-block"><p class="custom-block-title">适合谁读</p><ul><li>有开发经验，想系统补齐大模型、RAG、Agent 与 AI 编程实践的人</li><li>已经在用 AI，但仍觉得“会聊天，不会落地”的工程师或技术负责人</li><li>需要为团队做 AI 选型、架构判断或知识普及的负责人</li></ul></div><h2 id="这套专栏怎么读" tabindex="-1">这套专栏怎么读 <a class="header-anchor" href="#这套专栏怎么读" aria-label="Permalink to &quot;这套专栏怎么读&quot;">​</a></h2><p>如果你是第一次系统学习，建议按下面的顺序阅读：</p><ol><li>先读“基础原理”，建立算力、模型、Token 与 Transformer 的最小认知闭环。</li><li>再读“Prompt 与可靠性”，理解为什么模型会失控、如何约束输出、如何降低幻觉。</li><li>接着读“AI 编程实践”，把模型带回真实代码库，看工具选型、重构、上下文工程如何影响效率。</li><li>然后进入 “RAG”，理解知识库系统为什么经常“能召回、答不对”，以及正确的工程链路长什么样。</li><li>最后读 “Agent 与应用”，把模型、工具、检索和系统工程拼起来，看一个完整 AI 应用如何设计。</li></ol><h2 id="知识地图" tabindex="-1">知识地图 <a class="header-anchor" href="#知识地图" aria-label="Permalink to &quot;知识地图&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;基础原理&quot;] --&gt; B[&quot;Prompt 与可靠性&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;AI 编程实践&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; D[&quot;RAG&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; E[&quot;Agent 与应用&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; D</span></span></code></pre></div><h2 id="阅读路线" tabindex="-1">阅读路线 <a class="header-anchor" href="#阅读路线" aria-label="Permalink to &quot;阅读路线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>你会解决什么问题</th><th>代表文章</th></tr></thead><tbody><tr><td>基础原理</td><td>为什么大模型这么吃算力？为什么会有上下文限制？</td><td><code>hardware-and-compute</code>、<code>what-is-model</code>、<code>llm-mechanisms</code></td></tr><tr><td>Prompt 与可靠性</td><td>为什么同样一句话，不同写法差这么多？怎么让输出更稳？</td><td><code>prompt-basics</code>、<code>advanced-prompting</code>、<code>hallucination</code></td></tr><tr><td>AI 编程实践</td><td>AI 编程工具差别到底在哪里？怎么让模型真正理解代码库？</td><td><code>tools-comparison</code>、<code>daily-efficiency</code>、<code>context-prompting</code></td></tr><tr><td>RAG</td><td>为什么知识库看起来搭起来了，回答还是不靠谱？</td><td><code>rag-intro</code>、<code>vector-database</code>、<code>rag-deep-dive</code></td></tr><tr><td>Agent 与应用</td><td>如何把模型变成一个可调用工具、可接系统、可观测的应用能力？</td><td><code>llm-apis</code>、<code>agent-development</code>、<code>chatbot-project</code></td></tr></tbody></table><h2 id="这次重构后的写法" tabindex="-1">这次重构后的写法 <a class="header-anchor" href="#这次重构后的写法" aria-label="Permalink to &quot;这次重构后的写法&quot;">​</a></h2><p>为了让内容更适合工程师阅读，后续文章会统一遵循下面的结构：</p><ul><li>先给出真实问题，而不是直接灌术语</li><li>解释机制时，补充适用条件、代价与边界</li><li>实践类文章优先讲架构判断、关键流程和反模式</li><li>每篇至少保留一个可复用的方法、一个图表或流程图、一组参考资料</li><li>时效敏感内容会明确标注资料基线日期，避免“旧知识伪装成常识”</li></ul><h2 id="推荐入口" tabindex="-1">推荐入口 <a class="header-anchor" href="#推荐入口" aria-label="Permalink to &quot;推荐入口&quot;">​</a></h2><ul><li>想先补理论：从 <a href="./ai-evolution.html">从人工智能到生成式 AI</a> 开始</li><li>想先做 Prompt：从 <a href="./prompt-basics.html">Prompt 核心框架</a> 开始</li><li>想先提升开发效率：从 <a href="./tools-comparison.html">主流 AI 编程工具选型指南</a> 开始</li><li>想先搭知识库：从 <a href="./rag-intro.html">初探 RAG 架构</a> 开始</li><li>想直接看应用设计：从 <a href="./agent-development.html">智能体开发实战</a> 开始</li></ul><h2 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h2><p>本文是专栏导读页。后续各篇会按统一风格持续重写与补充，优先保证内容专业、清晰、可复用，而不是追求“每段都很燃”。</p>`,17)])])}const m=a(o,[["render",d]]);export{u as __pageData,m as default};
